    public function outcome_encoding(float $outcomeId, float $side): float {
        /**
         * @ignore
         * computes the encoding for an outcome $side => encoding = 10 * $outcomeId . $side ($side 0 = YES, $side 1 = NO)
         * @param {int} $outcomeId integer outcome id
         * @param {int} $side outcome $side, 0 = YES, 1 = NO
         * @return {int} the outcome $side encoding
         */
        return $this->sum(10 * $outcomeId, $side);
    }

    public function outcome_asset_id(float $encoding): float {
        /**
         * @ignore
         * returns the asset id used for orders => 100_000_000 . $encoding, e.g. 100000010
         * @param {int} $encoding outcome side $encoding
         * @return {int} the asset id
         */
        return $this->sum(100000000, $encoding);
    }

    public function outcome_coin(float $encoding): string {
        /**
         * @ignore
         * returns the coin name used in API calls => #<$encoding>, e.g. #10 for outcome 1 side 0
         * @param {int} $encoding outcome side $encoding
         * @return {string} the coin name
         */
        return '#' . (string) $encoding;
    }

    public function outcome_token(float $encoding): string {
        /**
         * @ignore
         * returns the token name => +<$encoding>, e.g. +10
         * @param {int} $encoding outcome side $encoding
         * @return {string} the token name
         */
        return '+' . (string) $encoding;
    }

    public function parse_outcome_description(string $description): array {
        /**
         * @ignore
         * parses a $description string of the form class:priceBinary|underlying:BTC|expiry:20260503-0600|targetPrice:78213|period:1d into a dict
         * @param {string} $description the raw outcome $description string
         * @return {array} a dict of the parsed key/value pairs
         */
        if (!$description) {
            return array();
        }
        $parts = explode('|', $description);
        $result = array();
        for ($i = 0; $i < count($parts); $i++) {
            $part = $parts[$i];
            $colonIndex = mb_strpos($part, ':');
            if ($colonIndex > -1) {
                $key = mb_substr($part, 0, $colonIndex - 0);
                $value = mb_substr($part, $colonIndex + 1);
                $result[$key] = $value;
            }
        }
        return $result;
    }

    public function build_outcome_symbol(array $desc, float $side, float $outcomeId): string {
        /**
         * @ignore
         * builds a human-readable outcome from a parsed description and $side, e.g. BTC-ABOVE-78213-20260503:YES for $side 0 and BTC-ABOVE-78213-20260503:NO for $side 1
         * @param {array} $desc parsed outcome description
         * @param {int} $side outcome $side, 0 = YES, 1 = NO
         * @param {int} $outcomeId integer outcome id
         * @return {string} the outcome
         */
        $underlying = $this->safe_string($desc, 'underlying', 'OUTCOME' . (string) $outcomeId);
        $targetPrice = $this->safe_string($desc, 'targetPrice');
        $expiry = $this->safe_string($desc, 'expiry', '');
        // Parse $expiry => "20260503-0600" → "20260503"
        $expiryDate = $expiry ? explode('-', $expiry)[0] : '';
        $label = ($side === 0) ? 'YES' : 'NO';
        $base = strtoupper($underlying);
        if ($targetPrice) {
            $base = $base . '-ABOVE-' . $targetPrice;
        }
        if ($expiryDate) {
            $base = $base . '-' . $expiryDate;
        }
        return $base . ':' . $label;
    }

    public function slugify_upper(string $name): string {
        /**
         * @ignore
         * converts a $name into an $upper-case slug of alphanumeric $parts joined by hyphens
         * @param {string} $name the raw $name to slugify
         * @return {string} the $upper-case slug
         */
        $upper = ($name === null) ? '' : strtoupper($name);
        $allowed = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
        $chars = $this->string_to_chars_array($upper);
        $s = '';
        for ($i = 0; $i < count($chars); $i++) {
            $ch = $chars[$i];
            if (mb_strpos($allowed, $ch) !== false) {
                $s = $s . $ch;
            } else {
                $s = $s . '-';
            }
        }
        $rawParts = explode('-', $s);
        $parts = array();
        for ($i = 0; $i < count($rawParts); $i++) {
            if (strlen($rawParts[$i]) > 0) {
                $parts[] = $rawParts[$i];
            }
        }
        return implode('-', $parts);
    }

    public function build_outcome_parent_symbol(array $desc, float $outcomeId, $name = '', array $question = array ()): string {
        /**
         * @ignore
         * builds a market id (parent outcome without YES/NO) from a parsed description, e.g. BTC-ABOVE-78213-20260503 for priceBinary outcomes or OUTCOME-9345 for non-priceBinary outcomes using the $name field
         * @param {array} $desc parsed outcome description
         * @param {int} $outcomeId integer outcome id
         * @param {string} [$name] outcome $name
         * @param {array} [$question] linked $question object from outcomeMeta
         * @return {string} the parent market outcome
         */
        $underlying = $this->safe_string($desc, 'underlying');
        if ($underlying) {
            $targetPrice = $this->safe_string($desc, 'targetPrice');
            $expiry = $this->safe_string($desc, 'expiry', '');
            $expiryDate = $expiry ? explode('-', $expiry)[0] : '';
            $base = strtoupper($underlying);
            if ($targetPrice) {
                $base = $base . '-ABOVE-' . $targetPrice;
            }
            if ($expiryDate) {
                $base = $base . '-' . $expiryDate;
            }
            return $base;
        }
        $questionDescription = $this->safe_string($question, 'description');
        if ($questionDescription) {
            $questionDesc = $this->parse_outcome_description($questionDescription);
            $questionClass = $this->safe_string_lower($questionDesc, 'class');
            if ($questionClass === 'pricebucket') {
                $questionUnderlying = $this->safe_string($questionDesc, 'underlying');
                $questionExpiry = $this->safe_string($questionDesc, 'expiry', '');
                $expiryDate = $questionExpiry ? explode('-', $questionExpiry)[0] : '';
                $thresholdsRaw = $this->safe_string($questionDesc, 'priceThresholds', '');
                $indexStr = $this->safe_string($desc, 'index');
                $rawDescription = $this->safe_string_lower($desc, 'description', '');
                $nameLower = strtolower($name);
                if ($questionUnderlying && $thresholdsRaw && $indexStr !== null) {
                    $thresholdParts = explode(',', $thresholdsRaw);
                    $thresholds = array();
                    for ($i = 0; $i < count($thresholdParts); $i++) {
                        $trimmed = trim($thresholdParts[$i]);
                        if (strlen($trimmed) > 0) {
                            $thresholds[] = $trimmed;
                        }
                    }
                    $thresholdsLength = count($thresholds);
                    $index = $this->parse_to_int($indexStr);
                    if ($thresholdsLength > 0 && $index !== null) {
                        if ($index <= 0) {
                            $bucketLabel = 'BELOW-' . $thresholds[0];
                        } elseif ($index >= $thresholdsLength) {
                            $lastIdx = $thresholdsLength - 1;
                            $bucketLabel = 'ABOVE-' . $thresholds[$lastIdx];
                        } else {
                            $bucketLabel = 'BETWEEN-' . $thresholds[$index - 1] . '-' . $thresholds[$index];
                        }
                        $base = strtoupper($questionUnderlying) . '-' . $bucketLabel;
                        if ($expiryDate) {
                            $base = $base . '-' . $expiryDate;
                        }
                        return $base;
                    }
                }
                $isFallbackLike = ($rawDescription === 'other') || (mb_strpos($nameLower, 'fallback') !== false) || (mb_strpos($nameLower, 'other') !== false);
                if ($questionUnderlying && $isFallbackLike) {
                    $base = strtoupper($questionUnderlying) . '-OTHER';
                    if ($expiryDate) {
                        $base = $base . '-' . $expiryDate;
                    }
                    return $base;
                }
            }
        }
        $questionName = $this->safe_string($question, 'name');
        if ($questionName) {
            $questionSlug = $this->slugify_upper($questionName);
            if ($questionSlug) {
                $outcomeSlug = $this->slugify_upper($name);
                $genericOutcomeNames = array(
                    'RECURRING' => true,
                    'RECURRING-FALLBACK' => true,
                    'RECURRING-NAMED-OUTCOME' => true,
                );
                if (is_array($genericOutcomeNames) && array_key_exists($outcomeSlug, $genericOutcomeNames)) {
                    if (mb_strpos($outcomeSlug, 'FALLBACK') !== false) {
                        $outcomeSlug = 'OTHER';
                    } else {
                        $outcomeSlug = '';
                    }
                }
                if ($outcomeSlug) {
                    return $questionSlug . '-' . $outcomeSlug . '-' . (string) $outcomeId;
                }
                return $questionSlug . '-' . (string) $outcomeId;
            }
        }
        // Fallback => use $name slugified, or OUTCOME-<id>
        if ($name) {
            return $this->slugify_upper($name) . '-' . (string) $outcomeId;
        }
        return 'OUTCOME-' . (string) $outcomeId;
    }

    public function fetch_markets($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * Retrieves all Hyperliquid $outcome $markets from outcomeMeta.
             * Each binary $outcome becomes one CCXT prediction $market with two outcomes => YES and NO.
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/asset-ids#outcomes
             *
             * @param {array} [$params] extra parameters
             * @return {Market[]} array of $market structures
             */
            //
            // outcomeMeta $response:
            //
            // {
            //   "outcomes" => array(
            //     array(
            //       "outcome" => 9345,
            //       "name" => "Recurring",
            //       "description" => "class:priceBinary|underlying:BTC|expiry:20260513-0300|targetPrice:81023|period:1d",
            //       "sideSpecs" => array(
            //         array( "name" => "Yes" ),
            //         array( "name" => "No" )
            //       )
            //     ),
            //     ...
            //   ),
            //   "questions" => [
            //     array(
            //       "question" => 182,
            //       "name" => "What will Hypurr eat the most of in May 2026?",
            //       "description" => "...",
            //       "fallbackOutcome" => 7002,
            //       "namedOutcomes" => [7003, 7004, 7005],
            //       "settledNamedOutcomes" => array()
            //     ),
            //     ...
            //   ]
            // }
            //
            $response = Async\await($this->publicPostInfo ($this->extend(array( 'type' => 'outcomeMeta' ), $params)));
            $outcomesList = $this->safe_list($response, 'outcomes', array());
            $questionsList = $this->safe_list($response, 'questions', array());
            $outcomesToQuestions = array();
            for ($qi = 0; $qi < count($questionsList); $qi++) {
                $question = $this->safe_dict($questionsList, $qi, array());
                $fallbackOutcome = $this->safe_integer($question, 'fallbackOutcome');
                if ($fallbackOutcome !== null) {
                    $fallbackKey = (string) $fallbackOutcome;
                    $outcomesToQuestions[$fallbackKey] = $question;
                }
                $namedOutcomes = $this->safe_list($question, 'namedOutcomes', array());
                for ($ni = 0; $ni < count($namedOutcomes); $ni++) {
                    $namedOutcomeId = $this->safe_integer($namedOutcomes, $ni);
                    if ($namedOutcomeId !== null) {
                        $namedKey = (string) $namedOutcomeId;
                        $outcomesToQuestions[$namedKey] = $question;
                    }
                }
            }
            $markets = array();
            if ($this->outcomes === null) {
                $this->outcomes = array();
            }
            if ($this->outcomes_by_id === null) {
                $this->outcomes_by_id = array();
            }
            for ($i = 0; $i < count($outcomesList); $i++) {
                $outcomeInfo = $this->safe_dict($outcomesList, $i, array());
                $outcomeId = $this->safe_integer($outcomeInfo, 'outcome', $i);
                $linkedQuestion = $this->safe_dict($outcomesToQuestions, (string) $outcomeId, array());
                $market = $this->parse_outcome_market($outcomeInfo, $outcomeId, $linkedQuestion);
                $markets[] = $market;
                // Build outcomes dictionary from $market outcomes
                $marketOutcomes = $this->safe_list($market, 'outcomes', array());
                for ($oi = 0; $oi < count($marketOutcomes); $oi++) {
                    $outcome = $this->safe_dict($marketOutcomes, $oi, array());
                    $outcomeSymbol = $this->safe_string_2($outcome, 'outcome', 'symbol');
                    $outcomeId_ = $this->safe_string_2($outcome, 'outcomeId', 'id');
                    if ($outcomeSymbol !== null) {
                        $this->outcomes[$outcomeSymbol] = $outcome;
                    }
                    if ($outcomeId_ !== null) {
                        $this->outcomes_by_id[$outcomeId_] = $outcome;
                    }
                }
            }
            return $markets;
        }) ();
    }

    public function parse_outcome_market(array $outcomeInfo, float $outcomeId, array $question = array ()): array {
        /**
         * @ignore
         * parses a single binary outcome market into a CCXT market structure with outcomesarray()
         * @param {array} $outcomeInfo raw entry from outcomeMeta $outcomes array
         * @param {int} $outcomeId integer outcome id
         * @param {array} [$question] linked $question object from outcomeMeta questions array
         * @return {array} a [market structure](https://docs.ccxt.com/#/?id=market-structure)
         */
        $description = $this->safe_string($outcomeInfo, 'description', '');
        $name = $this->safe_string($outcomeInfo, 'name', '');
        $sideSpecs = $this->safe_list($outcomeInfo, 'sideSpecs', array());
        $desc = $this->parse_outcome_description($description);
        $parentSymbol = $this->build_outcome_parent_symbol($desc, $outcomeId, $name, $question);
        $yesEncoding = $this->outcome_encoding($outcomeId, 0);
        $noEncoding = $this->outcome_encoding($outcomeId, 1);
        $yesOutcomeSymbol = $parentSymbol . ':YES';
        $noOutcomeSymbol = $parentSymbol . ':NO';
        // Parse $expiry from $description
        $expiry = $this->safe_string($desc, 'expiry');
        $expiryMs = null;
        $expiryDatetime = null;
        if ($expiry) {
            // e.g. "20260503-0600" → "2026-05-03T06:00:00Z"
            $expParts = explode('-', $expiry);
            $expPartsLength = count($expParts);
            if ($expPartsLength >= 1 && strlen($expParts[0]) === 8) {
                $ymd = $expParts[0];
                $hm = ($expPartsLength >= 2) ? $expParts[1] : '0000';
                $isoStr = mb_substr($ymd, 0, 4 - 0) . '-' . mb_substr($ymd, 4, 6 - 4) . '-' . mb_substr($ymd, 6, 8 - 6) . 'T' . mb_substr($hm, 0, 2 - 0) . ':' . mb_substr($hm, 2, 4 - 2) . ':00Z';
                $expiryMs = $this->parse8601($isoStr);
                $expiryDatetime = $isoStr;
            }
        }
        // Side labels from $sideSpecs (e.g. "Yes"/"No", but use YES/NO normalised)
        $yesLabel = $this->safe_string_upper($this->safe_dict($sideSpecs, 0, array()), 'name', 'YES');
        $noLabel = $this->safe_string_upper($this->safe_dict($sideSpecs, 1, array()), 'name', 'NO');
        $quoteCurrency = $this->safe_string($this->options, 'outcomeQuoteCurrency', 'USDH');
        $szDecimals = 4;  // $outcomes use 4 decimal places
        $active = true;
        $outcomePrecision = array(
            'amount' => (string) $this->parse_number($this->parse_precision($szDecimals)),
            'price' => 0.0001,
        );
        $outcomes = array(
            array(
                'id' => $this->outcome_coin($yesEncoding),
                'outcomeId' => $this->outcome_coin($yesEncoding),
                'outcome' => $yesOutcomeSymbol,
                'market' => $parentSymbol,
                'label' => $yesLabel,
                'active' => $active,
                'precision' => $outcomePrecision,
                'info' => array(
                    'encoding' => $yesEncoding,
                    'assetId' => $this->outcome_asset_id($yesEncoding),
                    'coinName' => $this->outcome_coin($yesEncoding),
                    'tokenName' => $this->outcome_token($yesEncoding),
                    'side' => 0,
                    'outcomeId' => $outcomeId,
                    'name' => $name,
                    'description' => $description,
                    'parsedDescription' => $desc,
                ),
            ),
            array(
                'id' => $this->outcome_coin($noEncoding),
                'outcomeId' => $this->outcome_coin($noEncoding),
                'outcome' => $noOutcomeSymbol,
                'market' => $parentSymbol,
                'label' => $noLabel,
                'active' => $active,
                'precision' => $outcomePrecision,
                'info' => array(
                    'encoding' => $noEncoding,
                    'assetId' => $this->outcome_asset_id($noEncoding),
                    'coinName' => $this->outcome_coin($noEncoding),
                    'tokenName' => $this->outcome_token($noEncoding),
                    'side' => 1,
                    'outcomeId' => $outcomeId,
                    'name' => $name,
                    'description' => $description,
                    'parsedDescription' => $desc,
                ),
            ),
        );
        return $this->safe_market_structure(array(
            'id' => (string) $outcomeId,
            'symbol' => $parentSymbol,
            'base' => explode('/', $parentSymbol)[0],
            'quote' => $quoteCurrency,
            'settle' => null,
            'baseId' => (string) $outcomeId,
            'quoteId' => $quoteCurrency,
            'settleId' => null,
            'type' => 'prediction',
            'marketType' => 'binary',
            'executionModel' => 'clob',
            'spot' => false,
            'margin' => null,
            'swap' => false,
            'future' => false,
            'option' => false,
            'prediction' => true,
            'active' => $active,
            'contract' => false,
            'linear' => null,
            'inverse' => null,
            'taker' => 0.0005,
            'maker' => 0.0002,
            'contractSize' => null,
            'expiry' => $expiryMs,
            'expiryDatetime' => $expiryDatetime,
            'strike' => null,
            'optionType' => null,
            'percentage' => true,
            'tierBased' => false,
            'feeSide' => 'get',
            'precision' => $outcomePrecision,
            'limits' => array(
                'leverage' => array( 'min' => null, 'max' => null ),
                'amount' => array( 'min' => null, 'max' => null ),
                'price' => array( 'min' => 0.0001, 'max' => 0.9999 ),
                'cost' => array( 'min' => $this->parse_number('1'), 'max' => null ),
            ),
            'outcomes' => $outcomes,
            'info' => $this->extend($outcomeInfo, array(
                'outcomeId' => $outcomeId,
                'parentSymbol' => $parentSymbol,
                'description' => $description,
                'parsedDescription' => $desc,
            )),
            'created' => null,
        ));
    }

    public function calculate_price_precision(float $midPx, float $szDecimals): float {
        /**
         * @ignore
         * calculates an appropriate price precision tick size given $midPx and $szDecimals
         * @param {float} $midPx the mid price
         * @param {int} $szDecimals the number of size decimals
         * @return {float} the price tick size
         */
        if ($midPx <= 0) {
            return 0.0001;
        }
        $midStr = $this->number_to_string($midPx);
        $parts = explode('.', $midStr);
        $intPart = $parts[0];
        $significantDigits = max (5, strlen($intPart));
        $maxDecimals = 8 - $szDecimals;
        $pricePrecisionDecimals = max (1, min ($maxDecimals, $significantDigits - strlen($intPart)));
        $zeros = '';
        $zeroCount = $pricePrecisionDecimals - 1;
        for ($zi = 0; $zi < $zeroCount; $zi++) {
            $zeros = $zeros . '0';
        }
        return $this->parse_to_numeric('0.' . $zeros . '1');
    }

    public function fetch_ticker(string $outcome, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $params) {
            /**
             * fetches a ticker for a single $outcome market using the L2 order book snapshot
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#l2-book-snapshot
             *
             * @param {string} $outcome unified $outcome (e.g. 'BTC-ABOVE-78213-20260503:YES')
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $coin = $this->safe_string($info, 'coinName');
            $request = array(
                'type' => 'l2Book',
                'coin' => $coin,
            );
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            //
            //     {
            //         "coin" => "#10",
            //         "levels" => array(
            //             [ array( "n" => "2", "px" => "0.44", "sz" => "500" ) ),   // bids [0]
            //             array( array( "n" => "2", "px" => "0.46", "sz" => "400" ) )    // asks [1]
            //         ],
            //         "time" => 1704290104840
            //     }
            //
            // l2Book returns null for coins without an order book; coerce to an empty dict
            $tickerData = $this->safe_dict(array( 'book' => $response ), 'book', array());
            return $this->parse_ticker($tickerData, $outcomeObj);
        }) ();
    }

    public function fetch_tickers(?array $outcomes = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcomes, $params) {
            /**
             * fetches all outcome market $tickers using allMids then optionally enriches with l2Book
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-all-$mids-for-all-actively-traded-coins
             *
             * @param {string[]} [$outcomes] filter by outcome ids or $outcomes
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a dictionary of [$ticker structures](https://docs.ccxt.com/#/?id=$ticker-structure)
             */
            $requestedOutcomeSymbols = array();
            if ($outcomes !== null) {
                for ($i = 0; $i < count($outcomes); $i++) {
                    $requested = $outcomes[$i];
                    $requestedOutcomeObj = Async\await($this->load_outcome($requested));
                    $requestedOutcome = $this->safe_string($requestedOutcomeObj, 'outcome', $requested);
                    $requestedOutcomeSymbols[$requestedOutcome] = true;
                }
            } else {
                // no filter — warm the whole outcome set so identities resolve from the cache
                Async\await($this->load_outcomes());
            }
            $response = Async\await($this->publicPostInfo ($this->extend(array( 'type' => 'allMids' ), $params)));
            //
            // array( "mids" => array( "#10" => "0.45", "#11" => "0.55", ... ) )
            //
            $mids = $this->safe_dict($response, 'mids', $response);
            $tickers = array();
            $outcomesMap = ($this->outcomes !== null) ? $this->outcomes : array();
            $outcomeHandles = is_array($outcomesMap) ? array_keys($outcomesMap) : array();
            for ($i = 0; $i < count($outcomeHandles); $i++) {
                $outcomeHandle = $outcomeHandles[$i];
                if ($outcomes !== null && !(is_array($requestedOutcomeSymbols) && array_key_exists($outcomeHandle, $requestedOutcomeSymbols))) {
                    continue;
                }
                $outcomeObj = $this->safe_dict($outcomesMap, $outcomeHandle, array());
                $info = $this->safe_dict($outcomeObj, 'info', array());
                $coin = $this->safe_string($info, 'coinName');
                $mid = $this->safe_number($mids, $coin);
                if ($mid === null) {
                    continue;
                }
                // Build minimal $ticker from $mid price
                $ticker = $this->parse_ticker(array( 'levels' => array( array(), array() ), 'mid' => $mid, 'time' => $this->milliseconds() ), $outcomeObj);
                $tickers[$outcomeHandle] = $ticker;
            }
            return $tickers;
        }) ();
    }

    public function parse_ticker(array $raw, ?array $market = null): array {
        /**
         * @ignore
         * parses a $raw l2Book response (or a synthetic $mid dict) into a unified ticker object
         * @param {array} $raw l2Book response or array( $mid, time ) object
         * @param {array} [$market] the $market the ticker belongs to
         * @return {array} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
         */
        //
        //     {
        //         "coin" => "#10",
        //         "levels" => array(
        //             [ array( "n" => "2", "px" => "0.44", "sz" => "500" ) ),   // bids [0]
        //             array( array( "n" => "2", "px" => "0.46", "sz" => "400" ) )    // asks [1]
        //         ],
        //         "time" => 1704290104840
        //     }
        //
        $now = $this->milliseconds();
        $timestamp = $this->safe_integer($raw, 'time', $now);
        // the 2nd arg carries the $outcome object (callers pass the resolved $outcome)
        $mkt = $this->safe_outcome(null, $market);
        $outcome = $this->safe_string($mkt, 'outcome');
        $levels = $this->safe_list($raw, 'levels', array());
        $rawBids = $this->safe_list($levels, 0, array());
        $rawAsks = $this->safe_list($levels, 1, array());
        $topBid = $this->safe_dict($rawBids, 0);
        $topAsk = $this->safe_dict($rawAsks, 0);
        $bid = ($topBid !== null) ? $this->safe_number($topBid, 'px') : null;
        $ask = ($topAsk !== null) ? $this->safe_number($topAsk, 'px') : null;
        $bidVolume = ($topBid !== null) ? $this->safe_number($topBid, 'sz') : null;
        $askVolume = ($topAsk !== null) ? $this->safe_number($topAsk, 'sz') : null;
        // Use synthetic $mid if no l2Book
        $mid = $this->safe_number($raw, 'mid');
        if ($mid === null && $bid !== null && $ask !== null) {
            $mid = $this->sum($bid, $ask) / 2;
        }
        // day volume lives on the parent market's $ctx; resolve it from the outcome's parent $market
        $parentSymbol = $this->safe_string($mkt, 'market');
        $parentMarket = ($parentSymbol !== null) ? $this->safe_market($parentSymbol) : null;
        $ctx = ($parentMarket !== null) ? $this->safe_dict($this->safe_dict($parentMarket, 'info', array()), 'ctx', array()) : array();
        $dayVolume = $this->safe_number($ctx, 'dayNtlVlm');
        return $this->safe_prediction_ticker(array(
            'outcome' => $outcome,
            'outcomeId' => $this->safe_string_2($mkt, 'outcomeId', 'id'),
            'label' => $this->safe_string($mkt, 'label'),
            'market' => $this->safe_string($mkt, 'market'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'high' => null,
            'low' => null,
            'bid' => $bid,
            'bidVolume' => $bidVolume,
            'ask' => $ask,
            'askVolume' => $askVolume,
            'vwap' => null,
            'open' => null,
            'close' => $mid,
            'last' => $mid,
            'previousClose' => null,
            'change' => null,
            'percentage' => null,
            'average' => $mid,
            'baseVolume' => null,
            'quoteVolume' => $dayVolume,
            'info' => $raw,
        ), $market);
    }

    public function fetch_order_book(string $outcome, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $limit, $params) {
            /**
             * fetches the L2 order book for an $outcome market
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#l2-book-snapshot
             *
             * @param {string} $outcome unified $outcome
             * @param {int} [$limit] max depth $levels (not used by hyperliquid but accepted)
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $request = array(
                'type' => 'l2Book',
                'coin' => $this->safe_string($info, 'coinName'),
            );
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            //
            //     {
            //         "coin" => "#10",
            //         "levels" => array(
            //             [ array( "n" => "5", "px" => "0.44", "sz" => "500" ), ... ),   // $bids [0]
            //             array( array( "n" => "5", "px" => "0.46", "sz" => "400" ), ... )    // $asks [1]
            //         ],
            //         "time" => 1704290104840
            //     }
            //
            $timestamp = $this->safe_integer($response, 'time');
            $levels = $this->safe_list($response, 'levels', array());
            $rawBids = $this->safe_list($levels, 0, array());
            $rawAsks = $this->safe_list($levels, 1, array());
            $bids = array();
            $asks = array();
            for ($i = 0; $i < count($rawBids); $i++) {
                $entry = $rawBids[$i];
                $bids[] = array( $this->safe_number($entry, 'px'), $this->safe_number($entry, 'sz') );
            }
            for ($i = 0; $i < count($rawAsks); $i++) {
                $entry = $rawAsks[$i];
                $asks[] = array( $this->safe_number($entry, 'px'), $this->safe_number($entry, 'sz') );
            }
            $orderbook = $this->parse_order_book(array( 'bids' => $bids, 'asks' => $asks ), $this->safe_string($outcomeObj, 'outcome', $outcome), $timestamp);
            return $this->safe_prediction_order_book($orderbook, $outcomeObj);
        }) ();
    }

    public function fetch_ohlcv(string $outcome, $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $timeframe, $since, $limit, $params) {
            /**
             * fetches candlestick OHLCV data for an $outcome $market
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#candle-snapshot
             *
             * @param {string} $outcome unified $outcome
             * @param {string} $timeframe '1m', '5m', '15m', '1h', '4h', '1d', etc.
             * @param {int} [$since] timestamp in ms of earliest candle
             * @param {int} [$limit] max number of candles
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {int} [$params->until] end timestamp in ms
             * @return {int[][]} a list of candles ordered, open, high, low, close, volume
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            // markets are keyed by the parent $market $outcome, not the $outcome handle ("MARKET:LABEL")
            $market = $this->market($this->safe_string($outcomeObj, 'market'));
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $until = $this->safe_integer($params, 'until', $this->milliseconds());
            $startTime = $since;
            if ($since === null) {
                $tf = $this->parse_timeframe($timeframe);
                $candleCount = ($limit !== null) ? $limit : 100;
                $startOffset = $tf * $candleCount * -1000;
                $startTime = $this->sum($until, $startOffset);
                if ($startTime < 0) {
                    $startTime = 0;
                }
            }
            $request = array(
                'type' => 'candleSnapshot',
                'req' => array(
                    'coin' => $this->safe_string($info, 'coinName'),
                    'interval' => $this->safe_string($this->timeframes, $timeframe, $timeframe),
                    'startTime' => $startTime,
                    'endTime' => $until,
                ),
            );
            $params = $this->omit($params, 'until');
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            //
            //     array(
            //         {
            //             "T" => 1704287699999,   // close time
            //             "c" => "0.45",
            //             "h" => "0.47",
            //             "i" => "1m",
            //             "l" => "0.43",
            //             "n" => 46,              // number of trades
            //             "o" => "0.44",
            //             "s" => "#10",
            //             "t" => 1704286800000,   // open time
            //             "v" => "1234.5"
            //         }
            //     )
            //
            return $this->parse_ohlcvs($response, $market, $timeframe, $since, $limit);
        }) ();
    }

    public function parse_ohlcv($ohlcv, ?array $market = null): array {
        /**
         * @ignore
         * parses a single hyperliquid candle object into a CCXT OHLCV tuple
         * @param {array} $ohlcv the raw candle object
         * @param {array} [$market] the $market the candle belongs to
         * @return {int[]} a candle ordered, open, high, low, close, volume
         */
        //
        //     {
        //         "T" => 1704287699999,   // close time
        //         "c" => "0.45",
        //         "h" => "0.47",
        //         "i" => "1m",
        //         "l" => "0.43",
        //         "n" => 46,              // number of trades
        //         "o" => "0.44",
        //         "s" => "#10",
        //         "t" => 1704286800000,   // open time
        //         "v" => "1234.5"
        //     }
        //
        return array(
            $this->safe_integer($ohlcv, 't'),
            $this->safe_number($ohlcv, 'o'),
            $this->safe_number($ohlcv, 'h'),
            $this->safe_number($ohlcv, 'l'),
            $this->safe_number($ohlcv, 'c'),
            $this->safe_number($ohlcv, 'v'),
        );
    }

    public function fetch_balance($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * Fetches spot $balance (outcomes use spot-like $balance).
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint/spot#retrieve-a-users-token-$balances
             *
             * @param {array} [$params] extra parameters
             * @param {string} [$params->user] wallet address (defaults to $this->walletAddress)
             * @return {Balances} $balance structure
             */
            list($userAddress, $params) = $this->handle_public_address('fetchBalance', $params);
            $request = array(
                'type' => 'spotClearinghouseState',
                'user' => $userAddress,
            );
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            //
            //     {
            //         "balances" => array(
            //             array( "coin" => "USDC",  "hold" => "0.0", "total" => "100.0" ),
            //             array( "coin" => "+10",   "hold" => "0.0", "total" => "50.0" ), // outcome token
            //             array( "coin" => "+11",   "hold" => "0.0", "total" => "25.0" )
            //         )
            //     }
            //
            $result = array(
                'info' => $response,
            );
            $balances = $this->safe_list($response, 'balances', array());
            for ($i = 0; $i < count($balances); $i++) {
                $balance = $balances[$i];
                $coin = $this->safe_string($balance, 'coin');
                $total = $this->safe_string($balance, 'total');
                $used = $this->safe_string($balance, 'hold');
                $account = $this->account();
                $account['total'] = $total;
                $account['used'] = $used;
                $result[$coin] = $account;
            }
            return $this->safe_balance($result);
        }) ();
    }

    public function fetch_positions(?array $outcomes = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcomes, $params) {
            /**
             * fetches the user's outcome $positions; outcome $positions are spot token $balances under the "+<encoding>" $coin form (size and entry notional), the value/entry/mark price/pnl are computed from the current mid prices
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint/spot#retrieve-a-users-token-$balances
             *
             * @param {string[]} [$outcomes] filter by outcome ids or $outcomes
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->user] wallet address
             * @return {array[]} a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
             */
            $requestedOutcomeSymbols = array();
            if ($outcomes !== null) {
                for ($i = 0; $i < count($outcomes); $i++) {
                    $requested = $outcomes[$i];
                    $requestedOutcomeObj = Async\await($this->load_outcome($requested));
                    $requestedOutcome = $this->safe_string($requestedOutcomeObj, 'outcome', $requested);
                    $requestedOutcomeSymbols[$requestedOutcome] = true;
                }
            } else {
                // no filter — warm the whole outcome set so identities resolve from the cache
                Async\await($this->load_outcomes());
            }
            list($userAddress, $params) = $this->handle_public_address('fetchPositions', $params);
            $request = array(
                'type' => 'spotClearinghouseState',
                'user' => $userAddress,
            );
            // outcome $positions are spot token $balances under the "+<encoding>" $coin form; they carry
            // the size (total) and entry notional (entryNtl). hyperliquid does not return the position
            // value / entry price / pnl, so they are computed from the current mid prices
            $promises = array(
                $this->publicPostInfo ($this->extend($request, $params)),
                $this->publicPostInfo (array( 'type' => 'allMids' )),
            );
            $results = Async\await(Promise\all($promises));
            $response = $results[0];
            $midsResponse = $results[1];
            $balances = $this->safe_list($response, 'balances', array());
            $mids = $this->safe_dict($midsResponse, 'mids', $midsResponse);
            $positions = array();
            for ($i = 0; $i < count($balances); $i++) {
                $balance = $this->safe_dict($balances, $i, array());
                $coin = $this->safe_string($balance, 'coin', '');
                // outcome tokens use the "+<encoding>" $balance form; skip regular spot tokens (USDC, ...)
                if (mb_strpos($coin, '+') !== 0) {
                    continue;
                }
                $totalStr = $this->safe_string($balance, 'total');
                if (($totalStr === null) || Precise::string_eq($totalStr, '0')) {
                    continue;
                }
                // the trade/orderbook form ("#<encoding>") resolves the outcome and the mid price
                $tradeCoin = '#' . mb_substr($coin, 1);
                $outcomeObj = $this->safe_outcome($tradeCoin);
                if ($outcomes !== null) {
                    $outcomeHandle = $this->safe_string($outcomeObj, 'outcome');
                    if ($outcomeHandle === null || !(is_array($requestedOutcomeSymbols) && array_key_exists($outcomeHandle, $requestedOutcomeSymbols))) {
                        continue;
                    }
                }
                $enriched = $this->extend($balance, array( 'markPx' => $this->safe_string($mids, $tradeCoin) ));
                $positions[] = $this->parse_position($enriched, $outcomeObj);
            }
            return $positions;
        }) ();
    }

    public function parse_position(array $position, ?array $market = null): array {
        /**
         * @ignore
         * parses a spot balance entry for an outcome token into a unified $position object
         * @param {array} $position the raw balance entry
         * @param {array} [$market] the outcome object the $position belongs to
         * @return {array} a [$position structure](https://docs.ccxt.com/#/?id=$position-structure)
         */
        // `$position` is a spotClearinghouseState balance entry (array( coin, $total, hold, entryNtl ))
        // enriched with the current mid price (markPx); hyperliquid does not return the $position
        // value / entry price / pnl for outcome tokens, so they are computed here
        $outcomeObj = $this->safe_outcome(null, $market);
        $totalStr = $this->safe_string($position, 'total');
        $total = $this->parse_number($totalStr);
        $entryNtlStr = $this->safe_string($position, 'entryNtl');
        $entryPrice = null;
        if (($entryNtlStr !== null) && ($totalStr !== null) && !Precise::string_eq($totalStr, '0')) {
            $entryPrice = $this->parse_number(Precise::string_div($entryNtlStr, $totalStr));
        }
        $markPxStr = $this->safe_string($position, 'markPx');
        $notional = null;        // current $position value = size * mark price
        $unrealizedPnl = null;   // value - entry $notional
        if (($markPxStr !== null) && ($totalStr !== null)) {
            $notionalStr = Precise::string_mul($totalStr, $markPxStr);
            $notional = $this->parse_number($notionalStr);
            if ($entryNtlStr !== null) {
                $unrealizedPnl = $this->parse_number(Precise::string_sub($notionalStr, $entryNtlStr));
            }
        }
        return $this->safe_prediction_position(array(
            'id' => null,
            'outcome' => $this->safe_string($outcomeObj, 'outcome'),
            'outcomeId' => $this->safe_string_2($outcomeObj, 'outcomeId', 'id'),
            'market' => $this->safe_string($outcomeObj, 'market'),
            'timestamp' => null,
            'datetime' => null,
            'isolated' => false,
            'hedged' => null,
            'side' => 'long',
            'contracts' => $total,
            'contractSize' => 1,
            'entryPrice' => $entryPrice,
            'markPrice' => $this->parse_number($markPxStr),
            'notional' => $notional,
            'leverage' => null,
            'collateral' => $this->safe_number($position, 'hold'),
            'initialMargin' => null,
            'maintenanceMargin' => null,
            'initialMarginPercentage' => null,
            'maintenanceMarginPercentage' => null,
            'unrealizedPnl' => $unrealizedPnl,
            'realizedPnl' => null,
            'liquidationPrice' => null,
            'marginRatio' => null,
            'marginMode' => 'cross',
            'percentage' => null,
            'info' => $position,
        ));
    }

    public function find_outcome_in_market(array $market, ?string $sideHint = null): array {
        $outcomesList = $this->safe_list($market, 'outcomes', array());
        $normalizedHint = $sideHint ? strtoupper($sideHint) : null;
        if ($normalizedHint !== null) {
            for ($i = 0; $i < count($outcomesList); $i++) {
                $oc = $this->safe_dict($outcomesList, $i, array());
                $ocSymbol = $this->safe_string_2($oc, 'outcome', 'symbol', '');
                $ocLabel = $this->safe_string_upper($oc, 'label');
                if ($ocLabel === $normalizedHint || str_ends_with($ocSymbol, ':' . $normalizedHint)) {
                    return $oc;
                }
            }
        }
        for ($i = 0; $i < count($outcomesList); $i++) {
            $oc = $this->safe_dict($outcomesList, $i, array());
            $info = $this->safe_dict($oc, 'info', array());
            if ($this->safe_integer($info, 'side') === 0) {
                return $oc;
            }
        }
        return $this->safe_dict($outcomesList, 0, array());
    }

    public function parse_outcome_input_side_hint(string $outcomeInput): ?string {
        if (!$outcomeInput) {
            return null;
        }
        $colonIndex = mb_strpos($outcomeInput, ':');
        if ($colonIndex > -1 && $colonIndex < strlen($outcomeInput) - 1) {
            $side = strtoupper(mb_substr($outcomeInput, $colonIndex + 1));
            if ($side === 'YES' || $side === 'NO') {
                return $side;
            }
        }
        $lower = strtolower($outcomeInput);
        if (str_ends_with($lower, '-yes')) {
            return 'YES';
        }
        if (str_ends_with($lower, '-no')) {
            return 'NO';
        }
        return null;
    }

    public function resolve_outcome_input(string $outcomeInput): array {
        if ($outcomeInput === null) {
            throw new ArgumentsRequired($this->id . ' resolveOutcomeInput() requires an outcome symbol or id');
        }
        if ($this->outcomes === null || $this->outcomes_by_id === null) {
            throw new ExchangeError($this->id . ' outcomes not loaded');
        }
        $sideHint = $this->parse_outcome_input_side_hint($outcomeInput);
        $candidates = array( $outcomeInput );
        if (str_starts_with($outcomeInput, '+')) {
            $candidates[] = '#' . mb_substr($outcomeInput, 1);
        }
        $digitChars = '0123456789';
        $inputChars = $this->string_to_chars_array($outcomeInput);
        $inputCharsLength = count($inputChars);
        $isNumericInput = $inputCharsLength > 0;
        for ($di = 0; $di < count($inputChars); $di++) {
            if (mb_strpos($digitChars, $inputChars[$di]) === false) {
                $isNumericInput = false;
                break;
            }
        }
        if ($isNumericInput) {
            $candidates[] = '#' . $outcomeInput; // encoding id without #
            $numeric = $this->parse_to_int($outcomeInput);
            if ($numeric !== null) {
                $candidates[] = $this->outcome_coin($this->outcome_encoding($numeric, 0)); // raw outcome id -> YES encoding
                $candidates[] = $this->outcome_coin($this->outcome_encoding($numeric, 1)); // raw outcome id -> NO encoding
            }
        }
        for ($i = 0; $i < count($candidates); $i++) {
            $key = $candidates[$i];
            if (is_array($this->outcomes) && array_key_exists($key, $this->outcomes)) {
                return $this->safe_dict($this->outcomes, $key, array());
            }
            if (is_array($this->outcomes_by_id) && array_key_exists($key, $this->outcomes_by_id)) {
                return $this->safe_dict($this->outcomes_by_id, $key, array());
            }
        }
        if ((is_array($this->markets) && array_key_exists($outcomeInput, $this->markets)) || (is_array($this->markets_by_id) && array_key_exists($outcomeInput, $this->markets_by_id))) {
            $market = $this->safe_market($outcomeInput);
            $sideHintOrDefault = ($sideHint !== null) ? $sideHint : 'YES';
            $found = $this->find_outcome_in_market($market, $sideHintOrDefault);
            if ($found > 0) {
                return $found;
            }
        }
        throw new ArgumentsRequired($this->id . ' cannot resolve outcome from input => ' . $outcomeInput . '. Provide an outcome symbol (e.g. MARKET:YES), outcome id (#<encoding>), or $market id with side.');
    }

    public function create_order(string $outcome, string $type, string $side, float $amount, ?float $price = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $type, $side, $amount, $price, $params) {
            /**
             * creates a limit or $market order for an $outcome $market
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/exchange-endpoint#place-an-order
             *
             * @param {string} $outcome unified $outcome
             * @param {string} $type 'limit' or 'market'
             * @param {string} $side 'buy' or 'sell'
             * @param {float} $amount quantity of $outcome tokens
             * @param {float} [$price] limit $price (0–1 range for prediction markets)
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->timeInForce] 'Gtc' | 'Ioc' | 'Alo' (default 'Gtc')
             * @param {boolean} [$params->postOnly] if true sets timeInForce to 'Alo'
             * @param {boolean} [$params->reduceOnly] if true, marks the order only so it can only decrease an existing position
             * @param {string} [$params->slippage] $slippage for $market orders (default 5%)
             * @param {string} [$params->clientOrderId] hex cloid
             * @param {string} [$params->vaultAddress] optional subaccount/vault address to trade on behalf of (master signer must be authorized)
             * @return {array} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
             */
            Async\await($this->initialize_client());
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            // markets are keyed by the parent $market $outcome; the $outcome handle ("MARKET:LABEL")
            // is not a $market id, so resolve the $market and price/amount precision via $outcomeObj['market']
            $marketSymbol = $this->safe_string($outcomeObj, 'market');
            $market = $this->market($marketSymbol);
            $outcomeInfo = $this->safe_dict($outcomeObj, 'info', array());
            $nonce = $this->milliseconds();
            $isBuy = (strtoupper($side) === 'BUY');
            $isMarket = (strtoupper($type) === 'MARKET');
            $assetId = $this->safe_integer($outcomeInfo, 'assetId');
            $clientOrderId = $this->safe_string_2($params, 'clientOrderId', 'client_id');
            $reduceOnly = $this->safe_bool($params, 'reduceOnly', false);
            $postOnly = $this->safe_bool($params, 'postOnly', false);
            $defaultSlippage = $this->safe_string($this->options, 'defaultSlippage', '0.05');
            $slippage = $this->safe_string($params, 'slippage', $defaultSlippage);
            $defaultTif = $isMarket ? 'Ioc' : 'Gtc';
            if ($postOnly) {
                $defaultTif = 'Alo';
            }
            $tif = $this->capitalize($this->safe_string_lower($params, 'timeInForce', $defaultTif)); // eslint-disable-line
            if ($price === null) {
                if ($isMarket) {
                    throw new ArgumentsRequired($this->id . ' createOrder() requires a reference $price for $market orders on $outcome markets in between 0 and 1. The exchange uses this reference $price together with the configured $slippage to derive the execution $price->');
                }
                throw new ArgumentsRequired($this->id . ' createOrder() requires a limit $price for $outcome markets in between 0 and 1.');
            }
            if ($isMarket) {
                $priceStr = $this->number_to_string($price);
                $px = $isBuy ? Precise::string_mul($priceStr, Precise::string_add('1', $slippage)) : Precise::string_mul($priceStr, Precise::string_sub('1', $slippage));
                $px = $this->price_to_precision($marketSymbol, $px);
            } else {
                $px = $this->price_to_precision($marketSymbol, $price);
            }
            $sz = $this->amount_to_precision($marketSymbol, $amount);
            $orderType = array(
                'limit' => array( 'tif' => $tif ),
            );
            $orderObj = array(
                'a' => $assetId,
                'b' => $isBuy,
                'p' => $px,
                's' => $sz,
                'r' => $reduceOnly,
                't' => $orderType,
            );
            if ($clientOrderId !== null) {
                $orderObj['c'] = $clientOrderId;
            }
            $vaultAddress = null;
            list($vaultAddress, $params) = $this->handle_option_and_params($params, 'createOrder', 'vaultAddress');
            $vaultAddress = $this->format_vault_address($vaultAddress);
            $orderAction = array(
                'type' => 'order',
                'orders' => array( $orderObj ),
                'grouping' => 'na',
            );
            $signature = $this->sign_l1_action($orderAction, $nonce, $vaultAddress);
            $request = array(
                'action' => $orderAction,
                'nonce' => $nonce,
                'signature' => $signature,
            );
            if ($vaultAddress !== null) {
                $request['vaultAddress'] = $vaultAddress;
            }
            $response = Async\await($this->privatePostExchange ($request));
            //
            //     {
            //         "status" => "ok",
            //         "response" => {
            //             "type" => "order",
            //             "data" => array( "statuses" => array( array( "resting" => array( "oid" => 12345 ) ) ) )
            //         }
            //     }
            //
            $responseObj = $this->safe_dict($response, 'response', array());
            $data = $this->safe_dict($responseObj, 'data', array());
            $statuses = $this->safe_list($data, 'statuses', array());
            $firstStatus = $this->safe_dict($statuses, 0, array());
            $resting = $this->safe_dict($firstStatus, 'resting', array());
            $filled = $this->safe_dict($firstStatus, 'filled', array());
            $oid = $this->safe_string($resting, 'oid', $this->safe_string($filled, 'oid'));
            $restingOid = $this->safe_string($resting, 'oid');
            $orderStatus = 'closed';
            if ($restingOid !== null) {
                $orderStatus = 'open';
            }
            return $this->safe_prediction_order(array(
                'id' => $oid,
                'clientOrderId' => $clientOrderId,
                'info' => $response,
                'timestamp' => $nonce,
                'datetime' => $this->iso8601($nonce),
                'status' => $orderStatus,
                'outcome' => $this->safe_string($outcomeObj, 'outcome', $outcome),
                'outcomeId' => $this->safe_string($outcomeObj, 'id'),
                'label' => $this->safe_string($outcomeObj, 'label'),
                'market' => $this->safe_string($outcomeObj, 'market'),
                'type' => $type,
                'side' => $side,
                'price' => $price,
                'amount' => $amount,
                'filled' => $this->safe_number($filled, 'totalSz'),
                'remaining' => null,
                'cost' => null,
                'fee' => null,
                'trades' => array(),
            ), $market);
        }) ();
    }

    public function cancel_order(string $id, ?string $outcome = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($id, $outcome, $params) {
            /**
             * cancels a single open order
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/exchange-endpoint#cancel-order-s
             *
             * @param {string} $id order $id
             * @param {string} [$outcome] unified $outcome
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->clientOrderId] cancel by client order $id
             * @param {string} [$params->vaultAddress] optional subaccount/vault address to cancel on behalf of
             * @return {array} an [order structure](https://docs.ccxt.com/#/?$id=order-structure)
             */
            $orders = Async\await($this->cancel_orders(array( $id ), $outcome, $params));
            return $this->safe_dict($orders, 0);
        }) ();
    }

    public function cancel_orders(array $ids, ?string $outcome = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($ids, $outcome, $params) {
            /**
             * cancels multiple open $orders
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/exchange-endpoint#cancel-$order-s
             *
             * @param {string[]} $ids $order $ids
             * @param {string} [$outcome] unified $outcome (required)
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [$order structures](https://docs.ccxt.com/#/?id=$order-structure)
             */
            $this->check_required_credentials();
            if ($outcome === null) {
                throw new ArgumentsRequired($this->id . ' cancelOrders() requires an $outcome argument');
            }
            Async\await($this->initialize_client());
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $outcomeInfo = $this->safe_dict($outcomeObj, 'info', array());
            $assetId = $this->safe_integer($outcomeInfo, 'assetId');
            $nonce = $this->milliseconds();
            $clientOrderId = $this->safe_value_2($params, 'clientOrderId', 'client_id');
            $params = $this->omit($params, array( 'clientOrderId', 'client_id' ));
            $cancelReq = array();
            $cancelAction = array( 'type' => 'cancel', 'cancels' => array() );
            if ($clientOrderId !== null) {
                $cloids = (gettype($clientOrderId) === 'array' && array_keys($clientOrderId) === array_keys(array_keys($clientOrderId))) ? $clientOrderId : array( $clientOrderId );
                $cancelAction['type'] = 'cancelByCloid';
                for ($i = 0; $i < count($cloids); $i++) {
                    $cancelReq[] = array( 'asset' => $assetId, 'cloid' => $cloids[$i] );
                }
            } else {
                $cancelAction['type'] = 'cancel';
                for ($i = 0; $i < count($ids); $i++) {
                    $cancelReq[] = array( 'a' => $assetId, 'o' => $this->parse_to_numeric($ids[$i]) );
                }
            }
            $cancelAction['cancels'] = $cancelReq;
            $vaultAddress = null;
            list($vaultAddress, $params) = $this->handle_option_and_params($params, 'cancelOrders', 'vaultAddress');
            $vaultAddress = $this->format_vault_address($vaultAddress);
            $signature = $this->sign_l1_action($cancelAction, $nonce, $vaultAddress);
            $request = array(
                'action' => $cancelAction,
                'nonce' => $nonce,
                'signature' => $signature,
            );
            if ($vaultAddress !== null) {
                $request['vaultAddress'] = $vaultAddress;
            }
            $response = Async\await($this->privatePostExchange ($request));
            $innerResponse = $this->safe_dict($response, 'response');
            $data = $this->safe_dict($innerResponse, 'data');
            $statuses = $this->safe_list($data, 'statuses', array());
            $outcomeSymbol = $this->safe_string($outcomeObj, 'outcome', $outcome);
            $requestIds = $ids;
            if ($clientOrderId !== null) {
                if ((gettype($clientOrderId) === 'array' && array_keys($clientOrderId) === array_keys(array_keys($clientOrderId)))) {
                    $requestIds = $clientOrderId;
                } else {
                    $requestIds = array( $clientOrderId );
                }
            }
            $orders = array();
            for ($i = 0; $i < count($statuses); $i++) {
                $status = $statuses[$i];
                $error = $this->safe_string($status, 'error');
                if ($error !== null) {
                    throw new OrderNotFound($this->id . ' cancelOrders() failed for ' . $this->safe_string($requestIds, $i, $this->safe_string($requestIds, 0)) . ' => ' . $error);
                }
                $success = ($status === 'success') || ($this->safe_string($status, 'status') === 'success');
                if (!$success) {
                    throw new ExchangeError($this->id . ' cancelOrders() received an unexpected $status => ' . $this->json($status));
                }
                $requestId = $this->safe_string($requestIds, $i, $this->safe_string($requestIds, 0));
                $order = array(
                    'id' => $requestId,
                    'clientOrderId' => ($clientOrderId !== null) ? $requestId : null,
                    'info' => $status,
                    'status' => 'canceled',
                    'outcome' => $outcomeSymbol,
                    'outcomeId' => $this->safe_string($outcomeObj, 'id'),
                    'label' => $this->safe_string($outcomeObj, 'label'),
                    'market' => $this->safe_string($outcomeObj, 'market'),
                    'timestamp' => $this->milliseconds(),
                    'datetime' => $this->iso8601($this->milliseconds()),
                );
                $orders[] = $this->safe_prediction_order($order);
            }
            return $orders;
        }) ();
    }

    public function fetch_open_orders(?string $outcome = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $since, $limit, $params) {
            /**
             * fetches currently open orders for the user
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-a-users-open-orders
             *
             * @param {string} [$outcome] filter by $outcome
             * @param {int} [$since] only return orders updated $since this timestamp in ms
             * @param {int} [$limit] max number of orders to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->user] wallet address
             * @param {string} [$params->method] 'openOrders' | 'frontendOpenOrders' (default)
             * @return {array[]} a list of [$order structures](https://docs.ccxt.com/#/?id=$order-structure)
             */
            list($userAddress, $params) = $this->handle_public_address('fetchOpenOrders', $params);
            list($method, $params) = $this->handle_option_and_params($params, 'fetchOpenOrders', 'method', 'frontendOpenOrders');
            $request = array( 'type' => $method, 'user' => $userAddress );
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            $ordersWithStatus = array();
            for ($i = 0; $i < count($response); $i++) {
                $order = $response[$i];
                $ordersWithStatus[] = $this->extend($order, array( 'ccxtStatus' => 'open' ));
            }
            $parsed = $this->parse_prediction_orders($ordersWithStatus, null, $since);
            $outcomeHandle = null;
            if ($outcome !== null) {
                Async\await($this->load_outcome($outcome));
                $outcomeObj = $this->outcome($outcome);
                $outcomeHandle = $this->safe_string($outcomeObj, 'outcome');
            }
            return $this->filter_by_outcome_since_limit($parsed, $outcomeHandle, $since, $limit);
        }) ();
    }

    public function fetch_orders(?string $outcome = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $since, $limit, $params) {
            /**
             * fetches all historical orders for the user
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-a-users-historical-orders
             *
             * @param {string} [$outcome] filter by $outcome
             * @param {int} [$since] only return orders updated $since this timestamp in ms
             * @param {int} [$limit] max number of orders to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->user] wallet address
             * @return {array[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
             */
            list($userAddress, $params) = $this->handle_public_address('fetchOrders', $params);
            $request = array( 'type' => 'historicalOrders', 'user' => $userAddress );
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            // Deduplicate by $oid keeping most recent statusTimestamp
            $deduped = array();
            for ($i = 0; $i < count($response); $i++) {
                $raw = $response[$i];
                $entry = $this->safe_dict($raw, 'order');
                if ($entry === null) {
                    $entry = $raw;
                }
                $oid = $this->safe_string($entry, 'oid');
                if ($oid !== null) {
                    if (!(is_array($deduped) && array_key_exists($oid, $deduped))) {
                        $deduped[$oid] = $raw;
                    } else {
                        $existingTs = $this->safe_integer($deduped[$oid], 'statusTimestamp');
                        $currentTs = $this->safe_integer($raw, 'statusTimestamp');
                        if ($currentTs !== null && ($existingTs === null || $currentTs > $existingTs)) {
                            $deduped[$oid] = $raw;
                        }
                    }
                }
            }
            $dedupedValues = is_array($deduped) ? array_values($deduped) : array();
            $parsed = $this->parse_prediction_orders($dedupedValues, null, $since);
            $outcomeHandle = null;
            if ($outcome !== null) {
                Async\await($this->load_outcome($outcome));
                $outcomeObj = $this->outcome($outcome);
                $outcomeHandle = $this->safe_string($outcomeObj, 'outcome');
            }
            return $this->filter_by_outcome_since_limit($parsed, $outcomeHandle, $since, $limit);
        }) ();
    }

    public function fetch_order(string $id, ?string $outcome = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($id, $outcome, $params) {
            /**
             * fetches a single order by $id
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#query-order-status-by-oid-or-cloid
             *
             * @param {string} $id order $id
             * @param {string} [$outcome] $outcome
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->user] wallet address
             * @param {string} [$params->clientOrderId] fetch by client order $id instead
             * @return {array} an [order structure](https://docs.ccxt.com/#/?$id=order-structure)
             */
            list($userAddress, $params) = $this->handle_public_address('fetchOrder', $params);
            $clientOrderId = $this->safe_string($params, 'clientOrderId');
            $request = array( 'type' => 'orderStatus', 'user' => $userAddress );
            if ($clientOrderId !== null) {
                $params = $this->omit($params, 'clientOrderId');
                $request['oid'] = $clientOrderId;
            } else {
                $isCloid = strlen($id) >= 34;
                $request['oid'] = $isCloid ? $id : $this->parse_to_numeric($id);
            }
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            $orderWrapper = $this->safe_dict($response, 'order', $response);
            $parsed = $this->parse_order($orderWrapper, null);
            if ($outcome !== null) {
                Async\await($this->load_outcome($outcome));
                $outcomeObj = $this->outcome($outcome);
                $expected = $this->safe_string($outcomeObj, 'outcome');
                if ($this->safe_string($parsed, 'outcome') !== $expected) {
                    throw new OrderNotFound($this->id . ' fetchOrder() order ' . $id . ' is not in $outcome ' . $expected);
                }
            }
            return $parsed;
        }) ();
    }

    public function parse_order(array $order, ?array $market = null): array {
        /**
         * @ignore
         * parses a raw hyperliquid $order object into a unified $order object
         * @param {array} $order the raw $order object
         * @param {array} [$market] the $market the $order belongs to
         * @return {array} an [$order structure](https://docs.ccxt.com/#/?id=$order-structure)
         */
        //
        // from frontendOpenOrders:
        // {
        //   "coin" => "#10",
        //   "limitPx" => "0.44",
        //   "oid" => 12345,
        //   "origSz" => "100",
        //   "side" => "B",
        //   "sz" => "100",
        //   "timestamp" => 1704346468838
        // }
        //
        // from historicalOrders / orderStatus:
        // {
        //   "order" => array( "coin" => "#10", "limitPx" => "0.44", "oid" => "12345", "origSz" => "100", "side" => "B", "sz" => "100", "tif" => "Gtc", "timestamp" => "1704346468838" ),
        //   "status" => "open",
        //   "statusTimestamp" => 1704346468838
        // }
        //
        $entry = $this->safe_dict($order, 'order', $order); // eslint-disable-line
        $status = $this->parse_order_status($this->safe_string_2($order, 'ccxtStatus', 'status'));
        $coin = $this->safe_string($entry, 'coin');
        $outcomeObj = $this->safe_outcome($coin, $market);
        $marketSymbol = $this->safe_string($outcomeObj, 'outcome');
        $resolvedMarket = $marketSymbol ? $this->safe_market($marketSymbol, $market) : $market;
        $sideRaw = $this->safe_string($entry, 'side');
        $side = ($sideRaw === 'B') ? 'buy' : 'sell';
        $totalAmount = $this->safe_string($entry, 'origSz');
        $remaining = $this->safe_string($entry, 'sz');
        $filled = null;
        if (($remaining !== null) && ($totalAmount !== null)) {
            $filled = Precise::string_sub($totalAmount, $remaining);
        }
        $timestamp = $this->safe_integer($entry, 'timestamp');
        $tifRaw = $this->safe_string($entry, 'tif');
        $tif = $this->parse_time_in_force($tifRaw);
        $postOnly = ($tif === 'PO');
        return $this->safe_prediction_order(array(
            'id' => $this->safe_string($entry, 'oid'),
            'clientOrderId' => $this->safe_string($entry, 'cloid'),
            'info' => $order,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'lastTradeTimestamp' => null,
            'status' => $status,
            'outcome' => $this->safe_string($outcomeObj, 'outcome'),
            'outcomeId' => $this->safe_string($outcomeObj, 'id'),
            'label' => $this->safe_string($outcomeObj, 'label'),
            'market' => $this->safe_string($outcomeObj, 'market'),
            'type' => $this->parse_order_type($this->safe_string($entry, 'orderType', 'limit')),
            'timeInForce' => $tif,
            'postOnly' => $postOnly,
            'reduceOnly' => $this->safe_bool($entry, 'reduceOnly', false),
            'side' => $side,
            'price' => $this->safe_number($entry, 'limitPx'),
            'triggerPrice' => $this->safe_bool($entry, 'isTrigger') ? $this->safe_number($entry, 'triggerPx') : null,
            'amount' => $this->parse_number($totalAmount),
            'cost' => null,
            'average' => $this->safe_number($entry, 'avgPx'),
            'filled' => $this->parse_number($filled),
            'remaining' => $this->parse_number($remaining),
            'fee' => null,
            'trades' => array(),
        ), $resolvedMarket);
    }

    public function parse_order_status(?string $status): ?string {
        $statuses = array(
            'triggered' => 'open',
            'filled' => 'closed',
            'open' => 'open',
            'canceled' => 'canceled',
            'rejected' => 'rejected',
            'marginCanceled' => 'canceled',
        );
        if ($status === null) {
            return null;
        }
        if (str_ends_with($status, 'Rejected')) {
            return 'rejected';
        }
        if (str_ends_with($status, 'Canceled')) {
            return 'canceled';
        }
        return $this->safe_string($statuses, $status, $status);
    }

    public function parse_order_type(?string $status): ?string {
        $statuses = array(
            'stop limit' => 'limit',
            'stop market' => 'market',
        );
        $statusLower = $status ? strtolower($status) : null;
        return $this->safe_string($statuses, $statusLower, $statusLower);
    }

    public function parse_time_in_force(?string $timeInForce): ?string {
        $statuses = array(
            'gtc' => 'GTC',
            'ioc' => 'IOC',
            'fok' => 'FOK',
            'alo' => 'PO',
        );
        $tifLower = $timeInForce ? strtolower($timeInForce) : null;
        return $this->safe_string($statuses, $tifLower, $timeInForce);
    }

    public function fetch_trades(string $outcome, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $since, $limit, $params) {
            /**
             * fetches the most recent public $trades for an $outcome
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-a-coins-recent-$trades
             *
             * @param {string} $outcome unified $outcome
             * @param {int} [$since] only return $trades at or after this timestamp in ms
             * @param {int} [$limit] the maximum number of $trades to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [trade structures](https://docs.ccxt.com/#/?id=trade-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $request = array(
                'type' => 'recentTrades',
                'coin' => $this->safe_string($info, 'coinName'),
            );
            // recentTrades returns the coin's most recent public $trades (newest first)
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            $trades = ($response) ? $response : array();
            return $this->parse_prediction_trades($trades, $outcomeObj, $since, $limit);
        }) ();
    }

    public function fetch_my_trades(?string $outcome = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $since, $limit, $params) {
            /**
             * fetches the authenticated user's fill history
             *
             * @see https://hyperliquid.gitbook.io/hyperliquid-docs/for-developers/api/info-endpoint#retrieve-a-users-$fills
             *
             * @param {string} [$outcome] filter by $outcome
             * @param {int} [$since] start timestamp in ms
             * @param {int} [$limit] max number of trades to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->user] wallet address
             * @param {int} [$params->until] end timestamp in ms
             * @return {array[]} a list of [trade structures](https://docs.ccxt.com/#/?id=trade-structure)
             */
            $outcomeHandle = null;
            if ($outcome !== null) {
                $outcomeObj = Async\await($this->load_outcome($outcome));
                $outcomeHandle = $this->safe_string($outcomeObj, 'outcome');
            } else {
                // $fills identify their $outcome only by the raw coin handle (e.g. "#10") — warm the
                // cache (one market load) so parseTrade can resolve the unified $outcome identity
                Async\await($this->load_outcomes());
            }
            list($userAddress, $params) = $this->handle_public_address('fetchMyTrades', $params);
            $request = array( 'user' => $userAddress );
            if ($since !== null) {
                $request['type'] = 'userFillsByTime';
                $request['startTime'] = $since;
            } else {
                $request['type'] = 'userFills';
            }
            $until = $this->safe_integer($params, 'until');
            $params = $this->omit($params, 'until');
            if ($until !== null) {
                $request['endTime'] = $until;
            }
            $response = Async\await($this->publicPostInfo ($this->extend($request, $params)));
            $fills = ($response) ? $response : array();
            // parse without an $outcome fallback — $fills span every market the wallet traded, so a
            // requested-$outcome fallback would mislabel $fills whose market is no longer listed
            $parsedTrades = $this->parse_prediction_trades($fills, null);
            return $this->filter_by_outcome_since_limit($parsedTrades, $outcomeHandle, $since, $limit);
        }) ();
    }

    public function parse_trade(array $trade, ?array $market = null): array {
        /**
         * @ignore
         * parses a single hyperliquid fill into a unified $trade object
         * @param {array} $trade the raw fill object
         * @param {array} [$market] the $market the $trade belongs to
         * @return {array} a [$trade structure](https://docs.ccxt.com/#/?id=$trade-structure)
         */
        //
        // {
        //   "closedPnl" => "0.19343",
        //   "coin" => "#10",
        //   "crossed" => true,
        //   "dir" => "Open Long",
        //   "fee" => "0.050062",
        //   "feeToken" => "USDC",
        //   "hash" => "0x...",
        //   "liquidationMarkPx" => null,
        //   "oid" => 12345,
        //   "px" => "0.44",
        //   "side" => "B",
        //   "startPosition" => "0",
        //   "sz" => "100",
        //   "tid" => 128423918764978,
        //   "time" => 1704262888911
        // }
        //
        $timestamp = $this->safe_integer($trade, 'time');
        $price = $this->safe_string($trade, 'px');
        $amount = $this->safe_string($trade, 'sz');
        $coin = $this->safe_string($trade, 'coin');
        $outcomeObj = $this->safe_outcome($coin, $market);
        $marketSymbol = $this->safe_string($outcomeObj, 'outcome');
        $resolvedMarket = $marketSymbol ? $this->safe_market($marketSymbol, $market) : $market;
        $rawSide = $this->safe_string($trade, 'side');
        $side = ($rawSide === 'B') ? 'buy' : 'sell';
        $fee = $this->safe_number($trade, 'fee');
        $feeCurrency = $this->safe_string($trade, 'feeToken', 'USDC');
        $outcomeSymbol = $this->safe_string($outcomeObj, 'outcome');
        $feeObject = null;
        if ($fee !== null) {
            $feeObject = array( 'cost' => $fee, 'currency' => $feeCurrency );
        }
        $cost = null;
        if (($price !== null) && ($amount !== null)) {
            $cost = $this->parse_number(Precise::string_mul($price, $amount));
        }
        return $this->safe_prediction_trade(array(
            'id' => $this->safe_string($trade, 'tid'),
            'info' => $trade,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'outcome' => $outcomeSymbol,
            'outcomeId' => $this->safe_string($outcomeObj, 'id'),
            'label' => $this->safe_string($outcomeObj, 'label'),
            'market' => $this->safe_string($outcomeObj, 'market'),
            'order' => $this->safe_string($trade, 'oid'),
            'type' => 'limit',
            'side' => $side,
            'takerOrMaker' => $this->safe_bool($trade, 'crossed') ? 'taker' : 'maker',
            'price' => $this->parse_number($price),
            'amount' => $this->parse_number($amount),
            'cost' => $cost,
            'fee' => $feeObject,
        ), $resolvedMarket);
    }

    public function fetch_events(array $params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * Groups outcome markets by their underlying (e.g. BTC-ABOVE-78213) into $event structures. Each $event contains both the YES and NO markets.
             * @param {array} [$params] extra parameters
             * @param {string} [$params->query] a single query string to filter by ($matches description/outcome)
             * @param {string[]} [$params->queries] multiple query strings (alternative to query)
             * @return {PredictionEvent[]} array of $event structures
             */
            $this->require_event_query($params);
            $queries = $this->parse_search_queries($params);
            // hyperliquid has no dedicated $events endpoint — $events are grouped from the outcome
            // markets, so fetch them directly rather than relying on $this->markets (which may be
            // unloaded or hold the non-prediction hyperliquid markets)
            $marketValues = Async\await($this->fetch_markets());
            // Group markets by $parentSymbol
            $groupMap = array();
            $lowerQueries = array();
            for ($i = 0; $i < count($queries); $i++) {
                $queryString = $queries[$i];
                $lowerQueries[] = strtolower($queryString);
            }
            $lowerQueriesLength = count($lowerQueries);
            for ($i = 0; $i < count($marketValues); $i++) {
                $mkt = $marketValues[$i];
                if (!$this->safe_bool($mkt, 'prediction', false)) {
                    continue;
                }
                $info = $this->safe_dict($mkt, 'info', array());
                $parentSymbol = $this->safe_string($info, 'parentSymbol', $this->safe_string($mkt, 'symbol'));
                // Apply query filter
                if ($lowerQueriesLength > 0) {
                    $description = strtolower($this->safe_string($info, 'description', ''));
                    $parentSymbolOrEmpty = ($parentSymbol !== null) ? $parentSymbol : '';
                    $symLower = strtolower($parentSymbolOrEmpty);
                    // the $parentSymbol uses hyphens (BTC-ABOVE-...), so match the $haystack $word-by-$word
                    // and require every $word of a query to appear, letting "BTC above" match BTC-ABOVE
                    $haystack = $description . ' ' . $symLower;
                    $matches = false;
                    for ($qi = 0; $qi < count($lowerQueries); $qi++) {
                        $words = explode(' ', $lowerQueries[$qi]);
                        $wordsLength = count($words);
                        $allWords = true;
                        for ($wi = 0; $wi < $wordsLength; $wi++) {
                            $word = $words[$wi];
                            if (($word !== '') && (mb_strpos($haystack, $word) === -1)) {
                                $allWords = false;
                                break;
                            }
                        }
                        if ($allWords) {
                            $matches = true;
                            break;
                        }
                    }
                    if (!$matches) {
                        continue;
                    }
                }
                if (!(is_array($groupMap) && array_key_exists($parentSymbol, $groupMap))) {
                    $groupMap[$parentSymbol] = array();
                }
                ($groupMap[$parentSymbol])[] = $mkt;
            }
            $events = array();
            $groupKeys = is_array($groupMap) ? array_keys($groupMap) : array();
            for ($gi = 0; $gi < count($groupKeys); $gi++) {
                $key = $groupKeys[$gi];
                $groupMarkets = $groupMap[$key];
                $event = $this->parse_event(array( 'parentSymbol' => $key, 'markets' => $groupMarkets ));
                $events[] = $event;
            }
            if (!$this->events) {
                $this->events = array();
            }
            for ($i = 0; $i < count($events); $i++) {
                $ev = $events[$i];
                $this->events[$ev['event']] = $ev;
            }
            return $this->apply_event_fetch_params($events, $params, $queries);
        }) ();
    }

    public function parse_event(array $raw): mixed {
        /**
         * @ignore
         * parses a grouped set of outcome $markets into a unified prediction event object
         * @param {array} $raw a dict with $parentSymbol and $markets entries
         * @return {array} an event structure
         */
        $parentSymbol = $this->safe_string($raw, 'parentSymbol');
        $markets = $this->safe_list($raw, 'markets', array());
        // Extract info from first market
        $marketsLength = count($markets);
        $firstMarket = ($marketsLength > 0) ? $markets[0] : array();
        $firstInfo = $this->safe_dict($firstMarket, 'info', array());
        $desc = $this->safe_dict($firstInfo, 'parsedDescription', array());
        $underlying = $this->safe_string($desc, 'underlying');
        $targetPrice = $this->safe_string($desc, 'targetPrice');
        $expiryRaw = $this->safe_string($desc, 'expiry');
        $expiryMs = null;
        $expiryDatetime = null;
        if ($expiryRaw) {
            $parts = explode('-', $expiryRaw);
            $partsLength = count($parts);
            if ($partsLength >= 1 && strlen($parts[0]) === 8) {
                $ymd = $parts[0];
                $hm = ($partsLength >= 2) ? $parts[1] : '0000';
                $isoStr = mb_substr($ymd, 0, 4 - 0) . '-' . mb_substr($ymd, 4, 6 - 4) . '-' . mb_substr($ymd, 6, 8 - 6) . 'T' . mb_substr($hm, 0, 2 - 0) . ':' . mb_substr($hm, 2, 4 - 2) . ':00Z';
                $expiryMs = $this->parse8601($isoStr);
                $expiryDatetime = $isoStr;
            }
        }
        $firstExpiry = $this->safe_integer($firstMarket, 'expiry');
        $title = $parentSymbol;
        if ($underlying !== null) {
            $titleSuffix = '';
            if ($targetPrice) {
                $titleSuffix = $titleSuffix . ' ABOVE ' . $targetPrice;
            }
            if ($expiryRaw) {
                $titleSuffix = $titleSuffix . ' @ ' . $expiryRaw;
            }
            $title = $underlying . $titleSuffix;
        }
        $endValue = ($expiryMs !== null) ? $expiryMs : $firstExpiry;
        return $this->extend(array(
            'id' => $parentSymbol,
            'slug' => $parentSymbol,
            'event' => $parentSymbol,
            'title' => $title,
            'markets' => $markets,
            'underlying' => $underlying,
            'targetPrice' => $targetPrice,
            'class' => $this->safe_string($desc, 'class'),
            'period' => $this->safe_string($desc, 'period'),
            'url' => null,
            'image' => null,
            'created' => null,
            'createdDatetime' => null,
            'end' => $endValue,
            'endDatetime' => $expiryDatetime,
            'category' => 'crypto',
            'lastUpdatedAt' => null,
            'resolutionSource' => 'Hyperliquid mark price',
            'resolved' => null,
            'info' => $raw,
        ));
    }

    public function amount_to_precision(string $outcome, mixed $amount): string {
        $market = $this->market($outcome);
        $prec = $this->safe_number($this->safe_dict($market, 'precision', array()), 'amount', 0.0001);
        // Convert precision to decimal places
        $decimals = 4;
        if ($prec > 0) {
            $decimals = $this->precision_from_string($this->number_to_string($prec));
        }
        return $this->decimal_to_precision($amount, 1, $decimals, 2, $this->paddingMode);
    }

    public function price_to_precision(string $outcome, mixed $price): string {
        $market = $this->market($outcome);
        $prec = $this->safe_number($this->safe_dict($market, 'precision', array()), 'price', 0.0001);
        $decimals = 4;
        if ($prec > 0) {
            $decimals = $this->precision_from_string($this->number_to_string($prec));
        }
        return $this->decimal_to_precision($price, 1, $decimals, 2, $this->paddingMode);
    }

    public function hash_message(mixed $message): string {
        return '0x' . $this->hash($message, 'keccak', 'hex');
    }

    public function sign_hash(string $hash, string $privateKey): array {
        $signature = $this->ecdsa(mb_substr($hash, -64), mb_substr($privateKey, -64), 'secp256k1', null);
        // assign to a bare local before padStart — `expr['key'].padStart()` leaks an null
        // padStart() call in the PHP transpiler (it only rewrites padStart on a bare identifier)
        $rRaw = $signature['r'];
        $sRaw = $signature['s'];
        $r = str_pad($rRaw, 64, '0', STR_PAD_LEFT);
        $s = str_pad($sRaw, 64, '0', STR_PAD_LEFT);
        return array(
            'r' => '0x' . $r,
            's' => '0x' . $s,
            'v' => $this->sum(27, $signature['v']), // ecrecover needs v in array(27,28), $this->ecdsareturns the raw array(0,1) recovery id
        );
    }

    public function sign_message(mixed $message, string $privateKey): array {
        return $this->sign_hash($this->hash_message($message), mb_substr($privateKey, -64));
    }

    public function construct_phantom_agent(mixed $hash, $isTestnet = true): array {
        $source = $isTestnet ? 'b' : 'a';
        return array(
            'source' => $source,
            'connectionId' => $hash,
        );
    }

    public function action_hash(array $action, ?string $vaultAddress, float $nonce): mixed {
        $dataBinary = $this->packb($action);
        $dataHex = bin2hex($dataBinary);
        $data = $dataHex;
        $data .= '00000' . $this->int_to_base16($nonce);
        if ($vaultAddress === null) {
            $data .= '00';
        } else {
            $data .= '01';
            $data .= $vaultAddress;
        }
        return $this->hash($this->base16_to_binary($data), 'keccak', 'binary');
    }

    public function sign_l1_action(array $action, float $nonce, ?string $vaultAddress = null): array {
        $this->check_required_credentials();
        $hash = $this->action_hash($action, $vaultAddress, $nonce);
        $isTestnet = $this->safe_bool($this->options, 'sandboxMode', false);
        $phantomAgent = $this->construct_phantom_agent($hash, $isTestnet);
        $zeroAddress = $this->safe_string($this->options, 'zeroAddress');
        $domain = array(
            'chainId' => 1337,
            'name' => 'Exchange',
            'verifyingContract' => $zeroAddress,
            'version' => '1',
        );
        $messageTypes = array(
            'Agent' => array(
                array( 'name' => 'source', 'type' => 'string' ),
                array( 'name' => 'connectionId', 'type' => 'bytes32' ),
            ),
        );
        $msg = $this->eth_encode_structured_data($domain, $messageTypes, $phantomAgent);
        return $this->sign_message($msg, $this->privateKey);
    }

    public function initialize_client(): PromiseInterface {
        return Async\async(function ()  {
            // createOrder/createOrders call this before trading; load markets so the order builder can
            // resolve the outcome's market and precision. loading them also keeps this method genuinely
            // async for the PHP and typed transpilers, which mishandle an async body that never suspends
            Async\await($this->load_markets());
            $buildFee = $this->safe_bool($this->options, 'builderFee', false);
            if (!$buildFee) {
                return null;
            }
            // builder fee approval would go here if needed
            return null;
        }) ();
    }

    public function handle_public_address(string $methodName, array $params): mixed {
        $userAux = null;
        list($userAux, $params) = $this->handle_option_and_params_2($params, $methodName, 'user', 'subAccountAddress');
        $user = $userAux;
        list($user, $params) = $this->handle_option_and_params($params, $methodName, 'address', $userAux);
        if ($user !== null && $user !== '') {
            return array( $user, $params );
        }
        if ($this->walletAddress !== null && $this->walletAddress !== '') {
            return array( $this->walletAddress, $params );
        }
        throw new ArgumentsRequired($this->id . ' ' . $methodName . '() requires a $user parameter or walletAddress to be set');
    }

    public function format_vault_address(?string $address = null): ?string {
        if ($address === null) {
            return null;
        }
        $normalized = $address;
        if (str_starts_with($normalized, '0x') || str_starts_with($normalized, '0X')) {
            $normalized = mb_substr($normalized, 2);
        }
        return strtolower($normalized);
    }

    public function sign(mixed $path, mixed $api = 'public', $method = 'POST', $params = array (), mixed $headers = null, mixed $body = null) {
        $apiGroup = (gettype($api) === 'array' && array_keys($api) === array_keys(array_keys($api))) ? $api[0] : $api;
        $sandboxMode = $this->safe_bool($this->options, 'sandboxMode', false);
        if ($sandboxMode) {
            $testUrls = $this->safe_dict($this->urls, 'test', array());
            $baseUrl = $this->safe_string($testUrls, $apiGroup, $this->safe_string($testUrls, 'public', ''));
        } else {
            $apiUrls = $this->safe_dict($this->urls, 'api', array());
            $baseUrl = $this->safe_string($apiUrls, $apiGroup, $this->safe_string($apiUrls, 'public', ''));
        }
        $url = $baseUrl . '/' . $path;
        if ($method === 'POST') {
            $headers = array( 'Content-Type' => 'application/json' );
            $body = $this->json($params);
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, mixed $response, mixed $requestHeaders, mixed $requestBody) {
        if (!$response) {
            return null;
        }
        $status = $this->safe_string($response, 'status', '');
        if ($status === 'err') {
            $message = $this->safe_string($response, 'response', $body);
            $feedback = $this->id . ' ' . $body;
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $message, $feedback);
            throw new ExchangeError($feedback);
        }
        // Check for error $statuses in order responses
        $responsePayload = $this->safe_dict($response, 'response', array());
        $data = $this->safe_dict($responsePayload, 'data', array());
        $statuses = $this->safe_list($data, 'statuses', array());
        for ($i = 0; $i < count($statuses); $i++) {
            $message = $this->safe_string($statuses[$i], 'error');
            if ($message !== null) {
                $feedback = $this->id . ' ' . $body;
                $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
                $this->throw_broadly_matched_exception($this->exceptions['broad'], $message, $feedback);
                throw new ExchangeError($feedback);
            }
        }
        return null;
    }

    public function calculate_rate_limiter_cost($api, $method, $path, $params, $config = array ()) {
        if ((is_array($config) && array_key_exists('byType', $config)) && (is_array($params) && array_key_exists('type', $params))) {
            $type = $params['type'];
            $byType = $config['byType'];
            if (is_array($byType) && array_key_exists($type, $byType)) {
                return $byType[$type];
            }
        }
        return $this->safe_value($config, 'cost', 1);
    }
}
